{
  "document_title": "这就是股市最强心法",
  "author": "北京炒家",
  "publish_date": "2020-03-12",
  "topic": "A股超短线交易策略",
  "key_concepts": [
    {
      "name": "龙头战法",
      "definition": "以五板为界限确认市场领涨股（龙头），在龙头确立后积极参与，无惧波动。"
    },
    {
      "name": "情绪周期",
      "definition": "股市存在‘启动-高潮-退潮-冰点’的轮回。策略需根据周期阶段调整（如高潮期做接力，退潮期空仓）。"
    },
    {
      "name": "弱转强",
      "definition": "前一日烂板（分歧），次日高开（一致），是高胜率的买入信号。"
    }
  ],
  "trading_rules": [
    "环境不行看首板",
    "四板烂板次日高开主要抢",
    "五板封住定龙头",
    "板块爆发去弱留强",
    "亏钱扩散停止接力",
    "早盘弱势应空仓"
  ],
  "risk_warnings": [
    "高位跟风股直线拉升不要碰",
    "尾盘炸板有风险",
    "切忌盲目逆向投资（别人贪婪我恐惧）而忽视市场客观走势"
  ]
}
